---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  buttons: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  image: {
    src: ImageMetadata
    alt: string
  }
}

const { class: className, title, description, buttons, image } = Astro.props
---

<Section
  class={cn("dark bg-background min-h-[80vh] justify-center", className)}
>
  <SectionContainer class="relative z-10 items-center gap-8 text-center">
    <h1
      class="text-foreground max-w-4xl text-4xl leading-[1.1] font-semibold tracking-tight text-balance sm:text-5xl lg:text-6xl"
    >
      {title}
    </h1>
    <p
      class="text-foreground/80 max-w-2xl text-lg leading-relaxed text-balance"
    >
      {description}
    </p>
    <div class="flex flex-wrap justify-center gap-3">
      {
        buttons.map(({ href, label, ...button }, index) => (
          <Button
            as="a"
            href={href}
            size="lg"
            variant={button.variant ?? (index === 0 ? "default" : "secondary")}
            {...button}
          >
            {label}
          </Button>
        ))
      }
    </div>
  </SectionContainer>
  <div class="bg-background pointer-events-none absolute inset-0">
    <Image
      src={image.src}
      alt={image.alt}
      class="size-full object-cover opacity-50"
      widths={[640, 960, 1280, 1920]}
      sizes="100vw"
      loading="eager"
    />
  </div>
</Section>
